import boto3
import json
from PIL import Image
import io

def lambda_handler(event, context):
    s3 = boto3.client('s3')
    sns = boto3.client('sns')

    # Get the bucket name and object key from the event
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']

    # Read the image from S3
    response = s3.get_object(Bucket=bucket_name, Key=object_key)
    image_data = response['Body'].read()

    # Process the image (example: resize it)
    image = Image.open(io.BytesIO(image_data))
    resized_image = image.resize((100, 100))

    # Save the processed image to S3
    output_buffer = io.BytesIO()
    resized_image.save(output_buffer, format='JPEG')
    s3.put_object(Bucket=bucket_name, Key=f'processed_{object_key}', Body=output_buffer.getvalue())

    # Send a notification via SNS
    sns.publish(
        TopicArn='arn:aws:sns:us-east-1:123456789012:MyTopic',
        Message=json.dumps({'default': f'Image {object_key} processed and saved.'}),
        Subject='Image Processing Notification'
    )

    # Log to CloudWatch
    print(f'Processed image {object_key}')

    return {
        'statusCode': 200,
        'body': json.dumps('Image processing completed successfully.')
    }